"use client"

import { useState, useEffect } from "react"
import { useDataStore, type DMAManager, type DMA } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { usePageAccess } from "@/hooks/use-page-access"
import { PageHeader } from "@/components/shared/page-header"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  Plus,
  UserCog,
  CheckCircle2,
  XCircle,
  Users,
  MapPin,
  Mail,
  Phone,
  Sparkles,
  Unlink,
  AlertTriangle,
  Building2,
  Lock,
  Eye,
  EyeOff,
} from "lucide-react"
import { toast } from "sonner"
import { cn } from "@/lib/utils"
import type { EntityStatus } from "@/lib/types"

export default function DMAManagersPage() {
  usePageAccess() // Check if user has access to this page

  const { currentUser } = useAuthStore()
  const {
    dmaManagers,
    dmas,
    utilities,
    fetchDMAManagers,
    fetchDMAs,
    fetchUtilities,
    addDMAManager,
    updateDMAManager,
    deleteDMAManager,
  } = useDataStore()

  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [editingManager, setEditingManager] = useState<DMAManager | null>(null)
  const [deleteId, setDeleteId] = useState<string | null>(null)
  const [unassignId, setUnassignId] = useState<string | null>(null)

  // Form state
  const [formName, setFormName] = useState("")
  const [formEmail, setFormEmail] = useState("")
  const [formPhone, setFormPhone] = useState("")
  const [formPassword, setFormPassword] = useState("")
  const [formConfirmPassword, setFormConfirmPassword] = useState("")
  const [showPassword, setShowPassword] = useState(false)
  const [formDMAId, setFormDMAId] = useState("unassigned")
  const [formStatus, setFormStatus] = useState<EntityStatus>("active")

  // Fetch data on mount
  useEffect(() => {
    fetchDMAManagers()
    fetchDMAs()
    fetchUtilities()
  }, [fetchDMAManagers, fetchDMAs, fetchUtilities])

  const isAdmin = currentUser?.role === "admin"
  const isUtilityManager = currentUser?.role === "utility_manager"

  // Get utility info for the current utility manager
  const myUtilityId = currentUser?.utilityId

  const myUtility = isUtilityManager
    ? utilities.find((u) => u.id === myUtilityId)
    : null
  const myUtilityDisplayName = myUtility?.name || currentUser?.utilityName || "Your Utility"

  // Filter managers based on user role - check both direct utilityId and through DMA's utilityId
  let visibleManagers = dmaManagers
  if (isUtilityManager && myUtilityId) {
    visibleManagers = dmaManagers.filter((m) => {
      // Direct utilityId match
      if (m.utilityId === myUtilityId) return true
      // Or accessible through their assigned DMA
      const dma = dmas.find((d) => d.id === m.dmaId)
      return dma?.utilityId === myUtilityId
    })
  }

  // Get DMAs that are available for assignment
  const availableDMAs = dmas.filter((d) => {
    // Filter by utility
    if (d.utilityId !== myUtilityId) return false
    // Filter by active status
    if (d.status !== "active") return false
    // If editing, allow unassigned or currently assigned
    if (editingManager) {
      return !d.managerId || d.managerId === editingManager.id
    }
    // If creating, only show unassigned
    return !d.managerId
  })

  // Filter managers for search
  const filteredManagers = visibleManagers.filter((m) => {
    const searchLower = search.toLowerCase().trim()
    if (!searchLower) return true

    const matchesName = m.name?.toLowerCase().includes(searchLower)
    const matchesEmail = m.email?.toLowerCase().includes(searchLower)
    const matchesPhone = m.phone?.toLowerCase().includes(searchLower)
    const matchesDMA = m.dmaName?.toLowerCase().includes(searchLower)
    const matchesUtility = m.utilityName?.toLowerCase().includes(searchLower)
    const matchesStatus = m.status?.toLowerCase().includes(searchLower)

    return (
      matchesName ||
      matchesEmail ||
      matchesPhone ||
      matchesDMA ||
      matchesUtility ||
      matchesStatus
    )
  })

  // Calculate stats
  const stats = {
    total: visibleManagers.length,
    active: visibleManagers.filter((m) => m.status === "active").length,
    assigned: visibleManagers.filter((m) => m.dmaId).length,
    unassigned: visibleManagers.filter((m) => !m.dmaId).length,
  }

  function openCreateDialog() {
    setEditingManager(null)
    setFormName("")
    setFormEmail("")
    setFormPhone("")
    setFormPassword("")
    setFormConfirmPassword("")
    setFormDMAId("unassigned")
    setFormStatus("active")
    setShowPassword(false)
    setDialogOpen(true)
  }

  function openEditDialog(manager: DMAManager) {
    setEditingManager(manager)
    setFormName(manager.name)
    setFormEmail(manager.email)
    setFormPhone(manager.phone || "")
    setFormPassword("") // Don't pre-fill password on edit
    setFormConfirmPassword("")
    setFormDMAId(manager.dmaId || "unassigned")
    setFormStatus(manager.status)
    setShowPassword(false)
    setDialogOpen(true)
  }

  async function handleSubmit() {
    // Validate required fields
    if (!formName.trim()) {
      toast.error("Manager name is required")
      return
    }
    if (!formEmail.trim()) {
      toast.error("Email is required")
      return
    }
    if (!editingManager && !formPassword.trim()) {
      toast.error("Password is required for new managers")
      return
    }

    // Basic email validation
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formEmail)) {
      toast.error("Invalid email format")
      return
    }

    // Password validation
    if (!editingManager && !formPassword.trim()) {
      toast.error("Password is required for new managers")
      return
    }

    // Validate password length
    if (formPassword.trim() && formPassword.length < 6) {
      toast.error("Password must be at least 6 characters")
      return
    }

    // Validate password confirmation
    if (formPassword.trim() && formPassword !== formConfirmPassword) {
      toast.error("Passwords do not match")
      return
    }

    try {
      if (editingManager) {
        const updateData: Record<string, any> = {
          id: editingManager.id,
          name: formName,
          email: formEmail,
          phone: formPhone || null,
          status: formStatus,
          dmaId: formDMAId === "unassigned" ? null : formDMAId,
        }
        if (formPassword) {
          updateData.password = formPassword
        }
        await updateDMAManager(editingManager.id, updateData)
        toast.success("DMA Manager updated successfully")
      } else {
        const createData = {
          name: formName,
          email: formEmail,
          phone: formPhone || null,
          password: formPassword,
          status: formStatus,
          utilityId: myUtilityId || "",
          dmaId: formDMAId === "unassigned" ? null : formDMAId,
        }
        await addDMAManager(createData)
        toast.success("DMA Manager created successfully")
      }
      setDialogOpen(false)
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Operation failed"
      )
    }
  }

  async function handleDelete() {
    if (deleteId) {
      try {
        await deleteDMAManager(deleteId)
        toast.success("DMA Manager deleted successfully")
        setDeleteId(null)
      } catch (error) {
        toast.error(
          error instanceof Error ? error.message : "Failed to delete manager"
        )
      }
    }
  }

  async function handleUnassignDMA() {
    if (unassignId) {
      try {
        // Unassign by setting dmaId to null - only send the field we want to update
        await updateDMAManager(unassignId, { dmaId: null })
        toast.success("DMA unassigned successfully")
        setUnassignId(null)
      } catch (error) {
        toast.error(
          error instanceof Error ? error.message : "Failed to unassign DMA"
        )
      }
    }
  }

  // Only Admins and Utility Managers can access this page
  if (!isAdmin && !isUtilityManager) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="DMA Manager Management"
          description="Only Admins and Utility Managers can manage DMA Managers"
        />
        <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20">
          <CardContent className="py-16 text-center">
            <div className="flex flex-col items-center gap-4">
              <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                <UserCog className="h-8 w-8 text-slate-400" />
              </div>
              <div>
                <p className="text-lg font-semibold text-slate-800">
                  Access Restricted
                </p>
                <p className="text-sm text-slate-500 mt-1">
                  Only Admins and Utility Managers can manage DMA Managers
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Modern Header with Stats */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
              <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-lg shadow-violet-500/20">
                <UserCog className="h-5 w-5 text-white" />
              </div>
              DMA Manager Management
            </h1>
            <p className="text-slate-500 mt-1">
              Manage all DMA Managers and their assignments
            </p>
          </div>
          <Button
            onClick={openCreateDialog}
            className="bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 hover:shadow-violet-500/40 transition-all duration-300 rounded-xl h-11 px-6"
          >
            <Plus className="h-4 w-4 mr-2" />
            Add Manager
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-4 gap-4">
          {/* Total Managers */}
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-violet-500/10 transition-all duration-300 bg-gradient-to-br from-violet-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-3">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-lg shadow-violet-500/20 group-hover:scale-110 transition-transform duration-300">
                  <UserCog className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">
                    Total Managers
                  </p>
                  <p className="text-2xl font-bold text-slate-800">
                    {stats.total}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Active Managers */}
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-emerald-500/10 transition-all duration-300 bg-gradient-to-br from-emerald-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-3">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-emerald-500 to-green-600 flex items-center justify-center shadow-lg shadow-emerald-500/20 group-hover:scale-110 transition-transform duration-300">
                  <CheckCircle2 className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">
                    Active Managers
                  </p>
                  <p className="text-2xl font-bold text-slate-800">
                    {stats.active}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Assigned DMAs */}
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-blue-500/10 transition-all duration-300 bg-gradient-to-br from-blue-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-3">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-500/20 group-hover:scale-110 transition-transform duration-300">
                  <MapPin className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">
                    With DMAs
                  </p>
                  <p className="text-2xl font-bold text-slate-800">
                    {stats.assigned}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Unassigned */}
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-amber-500/10 transition-all duration-300 bg-gradient-to-br from-amber-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-3">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-amber-500 to-orange-600 flex items-center justify-center shadow-lg shadow-amber-500/20 group-hover:scale-110 transition-transform duration-300">
                  <Unlink className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Unassigned</p>
                  <p className="text-2xl font-bold text-slate-800">
                    {stats.unassigned}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Modern Search */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-80">
          <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-violet-400/10 to-purple-500/10 blur-lg opacity-0 focus-within:opacity-100 transition-opacity duration-300 pointer-events-none" />
          <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400 pointer-events-none" />
          <Input
            placeholder="Search by name, email, DMA..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-11 h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20 shadow-sm"
          />
        </div>
        <div className="flex items-center gap-2 text-sm text-slate-500">
          <Users className="h-4 w-4" />
          <span>
            {filteredManagers.length} manager
            {filteredManagers.length !== 1 ? "s" : ""}
          </span>
        </div>
      </div>

      {/* Modern Cards Grid */}
      {filteredManagers.length === 0 ? (
        <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20">
          <CardContent className="py-16 text-center">
            <div className="flex flex-col items-center gap-4">
              <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                <UserCog className="h-8 w-8 text-slate-400" />
              </div>
              <div>
                <p className="text-lg font-semibold text-slate-800">
                  No managers found
                </p>
                <p className="text-sm text-slate-500 mt-1">
                  Get started by creating your first DMA Manager
                </p>
              </div>
              <Button
                onClick={openCreateDialog}
                className="mt-2 bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 rounded-xl"
              >
                <Plus className="h-4 w-4 mr-2" />
                Add Manager
              </Button>
            </div>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredManagers.map((manager) => {
            const dma = dmas.find((d) => d.id === manager.dmaId)
            return (
            <Card
              key={manager.id}
              className={cn(
                "border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group transition-all duration-300 hover:-translate-y-1",
                manager.status === "active"
                  ? "hover:shadow-xl hover:shadow-violet-500/10"
                  : "hover:shadow-xl hover:shadow-red-500/10 bg-gradient-to-br from-red-50/20 to-white"
              )}
            >
              {/* Gradient accent line */}
              <div
                className={cn(
                  "h-1",
                  manager.status === "active"
                    ? "bg-gradient-to-r from-violet-400 via-purple-500 to-violet-400"
                    : "bg-gradient-to-r from-red-400 via-rose-500 to-red-400"
                )}
              />

              <CardContent className="p-5">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div
                      className={cn(
                        "h-11 w-11 rounded-xl flex items-center justify-center shadow-lg transition-all duration-300 group-hover:scale-110",
                        manager.status === "active"
                          ? "bg-gradient-to-br from-violet-500 to-purple-600 shadow-violet-500/20"
                          : "bg-gradient-to-br from-red-500 to-rose-600 shadow-red-500/20"
                      )}
                    >
                      <UserCog className="h-5 w-5 text-white" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-slate-800">
                        {manager.name}
                      </h3>
                      <EntityStatusBadge status={manager.status} />
                    </div>
                  </div>

                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 rounded-lg hover:bg-slate-100"
                      >
                        <MoreHorizontal className="h-4 w-4 text-slate-500" />
                        <span className="sr-only">Actions</span>
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end" className="rounded-xl shadow-lg shadow-slate-200/50">
                      <DropdownMenuItem
                        onClick={() => openEditDialog(manager)}
                        className="rounded-lg"
                      >
                        <Pencil className="mr-2 h-4 w-4" />
                        Edit
                      </DropdownMenuItem>
                      {manager.dmaId && (
                        <DropdownMenuItem
                          onClick={() => setUnassignId(manager.id)}
                          className="text-amber-600 focus:text-amber-600 focus:bg-amber-50 rounded-lg"
                        >
                          <Unlink className="mr-2 h-4 w-4" />
                          Unassign DMA
                        </DropdownMenuItem>
                      )}
                      <DropdownMenuItem
                        onClick={() => setDeleteId(manager.id)}
                        className="text-red-600 focus:text-red-600 focus:bg-red-50 rounded-lg"
                      >
                        <Trash2 className="mr-2 h-4 w-4" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>

                {/* Manager Info */}
                <div className="space-y-3 mb-4 pb-4 border-b border-slate-100">
                  <div className="flex items-center gap-2 text-sm text-slate-600">
                    <Mail className="h-4 w-4 text-violet-500" />
                    <span className="truncate">{manager.email}</span>
                  </div>
                  {manager.phone && (
                    <div className="flex items-center gap-2 text-sm text-slate-600">
                      <Phone className="h-4 w-4 text-blue-500" />
                      <span>{manager.phone}</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2 text-sm text-slate-600">
                    <MapPin className="h-4 w-4 text-cyan-500" />
                    <span>
                      {dma ? (
                        <span className="font-medium text-slate-700">{dma.name}</span>
                      ) : (
                        <span className="text-slate-400 italic">Unassigned</span>
                      )}
                    </span>
                  </div>
                </div>

                {/* Stats Row */}
                <div className="flex items-center gap-2 text-xs text-slate-500">
                  <div className="px-2 py-1 rounded bg-slate-100/50 font-medium">
                    {manager.utilityName}
                  </div>
                </div>
              </CardContent>
            </Card>
            )
          })}
        </div>
      )}

      {/* Modern Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-lg bg-white/95 backdrop-blur-xl border-slate-200/50 shadow-2xl shadow-slate-200/50 rounded-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center">
                {editingManager ? (
                  <Pencil className="h-4 w-4 text-white" />
                ) : (
                  <Plus className="h-4 w-4 text-white" />
                )}
              </div>
              {editingManager ? "Edit DMA Manager" : "Add DMA Manager"}
            </DialogTitle>
            {editingManager && (
              <DialogDescription>
              Currently assigned to: <span className="font-semibold">{editingManager && dmas.find(d => d.id === editingManager.dmaId)?.name || editingManager?.dmaName || "Unassigned"}</span>
              </DialogDescription>
            )}
          </DialogHeader>
          <div className="flex flex-col gap-5 py-4 max-h-[60vh] overflow-y-auto">
            {/* Utility Information */}
            <div className="rounded-xl border border-violet-200/80 bg-gradient-to-r from-violet-50/50 to-purple-50/50 p-4">
              <div className="flex items-center gap-2 text-sm">
                <Building2 className="h-4 w-4 text-violet-600" />
                <span className="font-semibold text-violet-700">{myUtilityDisplayName}</span>
              </div>
              <p className="text-xs text-violet-500/80 mt-2">
                This DMA manager will be associated with above utility.
              </p>
            </div>

            {/* Name */}
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-name" className="text-sm font-medium text-slate-700">
                Manager Name <span className="text-red-500">*</span>
              </Label>
              <Input
                id="manager-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., John Mwangi"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>

            {/* Email */}
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-email" className="text-sm font-medium text-slate-700">
                Email <span className="text-red-500">*</span>
              </Label>
              <Input
                id="manager-email"
                type="email"
                value={formEmail}
                onChange={(e) => setFormEmail(e.target.value)}
                placeholder="john@example.com"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>

            {/* Phone */}
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-phone" className="text-sm font-medium text-slate-700">
                Phone Number
              </Label>
              <Input
                id="manager-phone"
                type="tel"
                value={formPhone}
                onChange={(e) => setFormPhone(e.target.value)}
                placeholder="+254 712 345 678"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>
            {/* DMA Assignment */}
            <div className="flex flex-col gap-2">
              <Label className="text-sm font-medium text-slate-700">
                Assign DMA
              </Label>
              <Select value={formDMAId} onValueChange={setFormDMAId}>
                <SelectTrigger className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl">
                  <SelectValue placeholder="Select a DMA (optional)" />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-lg shadow-slate-200/50">
                  <SelectItem value="unassigned" className="rounded-lg">
                    <span className="text-slate-500">None (Unassigned)</span>
                  </SelectItem>
                  {availableDMAs.map((dma) => (
                    <SelectItem key={dma.id} value={dma.id} className="rounded-lg">
                      <span>{dma.name}</span>
                      {dma.managerId && dma.managerId === editingManager?.id && (
                        <span className="text-slate-400 ml-2">(currently assigned)</span>
                      )}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Status */}
            <div className="flex flex-col gap-2">
              <Label className="text-sm font-medium text-slate-700">
                Status <span className="text-red-500">*</span>
              </Label>
              <Select value={formStatus} onValueChange={(v) => setFormStatus(v as EntityStatus)}>
                <SelectTrigger className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-lg shadow-slate-200/50">
                  <SelectItem value="active" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                      Active
                    </div>
                  </SelectItem>
                  <SelectItem value="inactive" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <XCircle className="h-4 w-4 text-slate-400" />
                      Inactive
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Password Section */}
            <div className="border-t border-slate-200 pt-4 flex flex-col gap-3">
              <Label className="flex items-center gap-2 text-sm font-medium text-slate-700">
                <Lock className="h-4 w-4" />
                {editingManager ? "Change Password (optional)" : "Account Password"}
              </Label>
              <div className="relative">
                <Input
                  type={showPassword ? "text" : "password"}
                  value={formPassword}
                  onChange={(e) => setFormPassword(e.target.value)}
                  placeholder={editingManager ? "Enter new password (optional)" : "Min 6 characters"}
                  className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl pr-10 focus:border-violet-400 focus:ring-violet-400/20"
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                  onClick={() => setShowPassword(!showPassword)}
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </Button>
              </div>
              <Input
                type={showPassword ? "text" : "password"}
                value={formConfirmPassword}
                onChange={(e) => setFormConfirmPassword(e.target.value)}
                placeholder="Confirm password"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button
              variant="outline"
              onClick={() => setDialogOpen(false)}
              className="rounded-xl"
            >
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              className="bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 rounded-xl"
            >
              {editingManager ? (
                <>
                  <Sparkles className="h-4 w-4 mr-2" />
                  Save Changes
                </>
              ) : (
                <>
                  <Plus className="h-4 w-4 mr-2" />
                  Create Manager
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={() => setDeleteId(null)}
        title="Delete DMA Manager"
        description="Are you sure you want to delete this DMA Manager? This action cannot be undone."
        confirmLabel="Delete Manager"
        onConfirm={handleDelete}
      />

      {/* Unassign DMA Confirmation */}
      <ConfirmDialog
        open={!!unassignId}
        onOpenChange={() => setUnassignId(null)}
        title="Unassign DMA"
        description="Are you sure you want to unassign the DMA from this manager? They will no longer manage this DMA."
        confirmLabel="Unassign DMA"
        onConfirm={handleUnassignDMA}
        variant="default"
      />
    </div>
  )
}
